document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("mobile-menu-button"),t=document.getElementById("mobile-menu");e&&t&&(e.addEventListener("click",()=>{const n=e.getAttribute("aria-expanded")==="true";e.setAttribute("aria-expanded",(!n).toString()),t.classList.toggle("hidden")}),document.addEventListener("click",n=>{const d=n.target;!e.contains(d)&&!t.contains(d)&&(e.setAttribute("aria-expanded","false"),t.classList.add("hidden"))}),document.addEventListener("keydown",n=>{n.key==="Escape"&&(e.setAttribute("aria-expanded","false"),t.classList.add("hidden"))}))});
